            cs.BorderLeft = (BorderStyle.Thin);
            cs.BorderRight = (BorderStyle.Thin);
            cs.BorderTop = (BorderStyle.Thin);
            cs.FillForegroundColor = ((short)0xA);
            cs.FillPattern = FillPattern.Bricks;
            fnt.Color = ((short)0xf);
