        public int GetCellIndex(SXSSFCell cell)
        {
            foreach (var entry in _cells)
            {
                if (entry.Value == cell)
                {
                    return entry.Key;
                }
            }
            return -1;
        }


        IEnumerator IEnumerable.GetEnumerator()
        {
            return this.GetEnumerator();
        }

        private List<ICell> GetSortedCells()
        {
            if (_sortedCellCache == null)
            {
                _sortedCellCache = _cells.OrderBy(kv => kv.Key).Select(kv => (ICell)kv.Value).ToList();
            }
            return _sortedCellCache;
        }

        /**
        * Create an iterator over the cells from [0, getLastCellNum()).
        * Includes blank cells, excludes empty cells
        * 
        * Returns an iterator over all filled cells (created via Row.createCell())
        * Throws ConcurrentModificationException if cells are added, moved, or
        * removed after the iterator is created.
        */
        public class FilledCellIterator : IEnumerator<ICell>
        {
            private readonly IEnumerator<SXSSFCell> enumerator;
            public FilledCellIterator(Dictionary<int, SXSSFCell> cells)
            {
                enumerator = cells.Values.GetEnumerator();
            }

            public ICell Current
            {
                get { return enumerator.Current; }
            }

            object IEnumerator.Current
            {
                get
                {
                    return enumerator.Current;
                }
            }

            public void Dispose()
            { 
            }

            public IEnumerator<ICell> GetEnumerator()
            {
                return enumerator;
            }

            public bool MoveNext()
            {
                return enumerator.MoveNext();
            }

            public void Reset()
            {
                enumerator.Reset();
            }
        }

        public class CellIterator : IEnumerator<ICell>
        {
            private readonly IDictionary<int, SXSSFCell> _cells;
            private readonly int maxColumn;
            private int pos;
            public CellIterator(int lastCellNum, IDictionary<int, SXSSFCell> cells)
            {
                maxColumn = lastCellNum; //last column PLUS ONE, SHOULD BE DERIVED from cells enum.
                pos = -1;
                _cells = cells;
            }


            public ICell Current
            {
                get
                {
                    return _cells.TryGetValue(pos, out SXSSFCell cell) ? cell: null;
                }
            }

            object IEnumerator.Current
            {
                get { return Current; }
            }

            public void Dispose()
            { }

            public IEnumerator<ICell> GetEnumerator()
            {
                throw new NotImplementedException();
            }

            public bool HasNext()
            {
                return pos < maxColumn;
            }

            public bool MoveNext()
            {
                if (HasNext())
                {
                    pos++;
                    return true;
                }

                return false;
            }

            public ICell Next()
            {
                if (HasNext())
                {
                    if (_cells.ContainsKey(pos))
                        return _cells[pos++];
                    else
                    {
                        pos++;
                        return null;
                    }
                }
                else
                    throw new NullReferenceException();
            }

            public void Remove()
            {
                throw new InvalidOperationException();
            }

            public void Reset()
            {
                throw new NotImplementedException();
            }


        }
    }



