using NPOI.XSSF.Streaming;
using NPOI.XSSF.UserModel;

static void Assert(bool condition, string message)
{
    if (!condition)
    {
        throw new Exception(message);
    }
}

static ICellStyle CreateStyle(IWorkbook workbook, string format)
{
    var style = workbook.CreateCellStyle();
    style.DataFormat = workbook.CreateDataFormat().GetFormat(format);
    return style;
}

static void AssertColumnStyleApplied(IWorkbook workbook, string label)
{
    var sheet = workbook.CreateSheet(label);
    var style = CreateStyle(workbook, "0.00");

    sheet.SetDefaultColumnStyle(0, style);
    var cell = sheet.CreateRow(1).CreateCell(0);
    cell.SetCellValue(12.34);

    Console.WriteLine($"{label}: expected {style.Index}; actual {cell.CellStyle?.Index}");
    Assert(cell.CellStyle != null && cell.CellStyle.Index == style.Index, $"{label} did not apply default column style");

    var unstyledCell = sheet.CreateRow(2).CreateCell(1);
    Assert(unstyledCell.CellStyle == null || unstyledCell.CellStyle.Index == 0, $"{label} styled an unrelated column");
}

static void AssertRowStylePrecedence()
{
    var workbook = new XSSFWorkbook();
    var sheet = workbook.CreateSheet("precedence");
    var columnStyle = CreateStyle(workbook, "0.00");
    var rowStyle = CreateStyle(workbook, "m/d/yy");

    sheet.SetDefaultColumnStyle(0, columnStyle);
    var row = sheet.CreateRow(0);
    row.RowStyle = rowStyle;
    var cell = row.CreateCell(0);

    Console.WriteLine($"XSSF row precedence: row {rowStyle.Index}; column {columnStyle.Index}; actual {cell.CellStyle?.Index}");
    Assert(cell.CellStyle != null && cell.CellStyle.Index == rowStyle.Index, "XSSF row style should keep precedence over column style");
}

AssertColumnStyleApplied(new XSSFWorkbook(), "XSSF");
AssertColumnStyleApplied(new SXSSFWorkbook(), "SXSSF");
AssertColumnStyleApplied(new HSSFWorkbook(), "HSSF");
AssertRowStylePrecedence();
Console.WriteLine("All default column style checks passed.");
EOF
